import{_ as a,o as r,c as i,ag as o}from"./chunks/framework.DGzMGr_a.js";const c=JSON.parse('{"title":"质量工程概述","description":"","frontmatter":{},"headers":[],"relativePath":"basic/quality-overview.md","filePath":"basic/quality-overview.md","lastUpdated":1782656175000}'),e={name:"basic/quality-overview.md"};function l(n,t,s,d,h,u){return r(),i("div",null,[...t[0]||(t[0]=[o('<h1 id="质量工程概述" tabindex="-1">质量工程概述 <a class="header-anchor" href="#质量工程概述" aria-label="Permalink to &quot;质量工程概述&quot;">​</a></h1><h2 id="质量的演变" tabindex="-1">质量的演变 <a class="header-anchor" href="#质量的演变" aria-label="Permalink to &quot;质量的演变&quot;">​</a></h2><p>质量的概念随着工业发展不断演进，经历了四个主要阶段：</p><h3 id="_1-检验质量-quality-by-inspection" tabindex="-1">1. 检验质量（Quality by Inspection） <a class="header-anchor" href="#_1-检验质量-quality-by-inspection" aria-label="Permalink to &quot;1. 检验质量（Quality by Inspection）&quot;">​</a></h3><p>20 世纪初期，质量管理以<strong>检验</strong>为核心。产品制造完成后，由专职检验人员逐件或抽样检查，将合格品与不合格品分离。这是一种<strong>事后把关</strong>的方式，无法预防缺陷的产生，而且全检成本高昂。代表人物是泰勒（Frederick Taylor），他在科学管理理论中首次将检验职能从生产中独立出来。</p><h3 id="_2-制造质量-quality-by-manufacturing" tabindex="-1">2. 制造质量（Quality by Manufacturing） <a class="header-anchor" href="#_2-制造质量-quality-by-manufacturing" aria-label="Permalink to &quot;2. 制造质量（Quality by Manufacturing）&quot;">​</a></h3><p>1920–1940 年代，统计质量控制（SQC）的诞生标志着质量进入制造阶段。休哈特（Walter Shewhart）提出了<strong>控制图</strong>（Control Chart）概念，用统计方法区分正常波动与异常波动，在生产过程中实时监控质量。这一阶段的核心思想是在<strong>制造过程中控制质量</strong>，而非仅靠最终检验。</p><h3 id="_3-设计质量-quality-by-design" tabindex="-1">3. 设计质量（Quality by Design） <a class="header-anchor" href="#_3-设计质量-quality-by-design" aria-label="Permalink to &quot;3. 设计质量（Quality by Design）&quot;">​</a></h3><p>1950–1970 年代，质量管理的重心前移到产品设计阶段。田口玄一（Genichi Taguchi）提出了<strong>田口方法</strong>（Taguchi Methods），强调通过实验设计（DOE）在设计和开发阶段就优化产品和过程参数，使产品对噪声因素不敏感，从根本上保证质量。</p><h3 id="_4-全面质量管理-tqm" tabindex="-1">4. 全面质量管理（TQM） <a class="header-anchor" href="#_4-全面质量管理-tqm" aria-label="Permalink to &quot;4. 全面质量管理（TQM）&quot;">​</a></h3><p>1980 年代至今，全面质量管理（Total Quality Management, TQM）成为主流。TQM 强调全员参与、持续改进、以客户为中心，将质量管理扩展到企业的所有职能部门——从研发、采购、生产到销售和售后服务，形成了系统化、全流程的质量管理文化。</p><hr><h2 id="质量大师" tabindex="-1">质量大师 <a class="header-anchor" href="#质量大师" aria-label="Permalink to &quot;质量大师&quot;">​</a></h2><h3 id="戴明-w-edwards-deming-与-14-要点" tabindex="-1">戴明（W. Edwards Deming）与 14 要点 <a class="header-anchor" href="#戴明-w-edwards-deming-与-14-要点" aria-label="Permalink to &quot;戴明（W. Edwards Deming）与 14 要点&quot;">​</a></h3><p>戴明被公认为现代质量管理之父。他提出的<strong>戴明 14 要点</strong>是质量管理的经典框架：</p><ol><li>建立持续改进产品和服务的长期目标</li><li>采用新的质量管理观念</li><li>停止依靠大规模检验来保证质量</li><li>不再以价格作为选择供应商的唯一标准</li><li>持续不断地改进生产和服务系统</li><li>建立岗位培训制度</li><li>建立领导力体系</li><li>消除恐惧，鼓励双向沟通</li><li>打破部门壁垒</li><li>取消对员工的口号、标语和量化指标</li><li>取消定额管理和目标管理</li><li>消除损害员工工作自豪感的障碍</li><li>建立积极的学习和自我改进机制</li><li>推动变革，让每个人参与其中</li></ol><p>戴明强调<strong>质量改进是管理层的责任</strong>，85% 的质量问题由管理系统引起，只有 15% 由一线员工造成。</p><h3 id="朱兰-joseph-m-juran-的质量三部曲" tabindex="-1">朱兰（Joseph M. Juran）的质量三部曲 <a class="header-anchor" href="#朱兰-joseph-m-juran-的质量三部曲" aria-label="Permalink to &quot;朱兰（Joseph M. Juran）的质量三部曲&quot;">​</a></h3><p>朱兰提出了<strong>质量三部曲</strong>（Quality Trilogy）：</p><ul><li><strong>质量规划（Quality Planning）</strong>：识别客户需求，制定质量目标，设计实现目标的流程</li><li><strong>质量控制（Quality Control）</strong>：建立控制标准，测量实际表现，与标准对比并采取纠正措施</li><li><strong>质量改进（Quality Improvement）</strong>：识别改进机会，组织改进团队，实施突破性改进</li></ul><p>朱兰还提出了<strong>帕累托原则</strong>在质量管理中的应用——80% 的质量问题源自 20% 的关键原因，因此应集中资源解决少数重要问题。</p><h3 id="克劳士比-philip-b-crosby-的零缺陷" tabindex="-1">克劳士比（Philip B. Crosby）的零缺陷 <a class="header-anchor" href="#克劳士比-philip-b-crosby-的零缺陷" aria-label="Permalink to &quot;克劳士比（Philip B. Crosby）的零缺陷&quot;">​</a></h3><p>克劳士比提出了<strong>零缺陷</strong>（Zero Defects）理念，核心观点包括：</p><ul><li><strong>质量是符合要求</strong>（Conformance to Requirements），而非&quot;好&quot;或&quot;优秀&quot;等主观描述</li><li><strong>预防为主</strong>（Prevention），而非检验</li><li><strong>零缺陷</strong>是可接受的工作标准，而非&quot;差不多就好&quot;</li><li><strong>质量成本</strong>是衡量质量表现的最佳指标</li></ul><p>克劳士比的名言：&quot;<strong>质量是免费的</strong>&quot;（Quality is Free）——第一次就把事情做对，远比事后返工更省钱。</p><hr><h2 id="现代质量工程核心领域" tabindex="-1">现代质量工程核心领域 <a class="header-anchor" href="#现代质量工程核心领域" aria-label="Permalink to &quot;现代质量工程核心领域&quot;">​</a></h2><p>质量工程包含三个层次，常被简称为 <strong>QCC/QE/QA/QM</strong>：</p><table tabindex="0"><thead><tr><th>层次</th><th>英文</th><th>中文</th><th>核心活动</th><th>关注点</th></tr></thead><tbody><tr><td>QC</td><td>Quality Control</td><td>质量控制</td><td>检验、测试、数据分析</td><td>发现和纠正缺陷</td></tr><tr><td>QA</td><td>Quality Assurance</td><td>质量保证</td><td>流程审核、体系审查</td><td>确保过程正确</td></tr><tr><td>QM</td><td>Quality Management</td><td>质量管理</td><td>战略制定、体系策划</td><td>整体质量体系运行</td></tr></tbody></table><ul><li><strong>QC（质量控制）</strong>：以产品为中心，使用统计工具（如控制图、直方图、检查表）监控生产过程中的质量波动，发现异常及时调整。QC 是质量工程的基础执行层。</li><li><strong>QA（质量保证）</strong>：以过程为中心，通过建立和执行质量管理体系（如 ISO 9001），确保所有影响质量的活动都按规范执行。QA 的核心是<strong>建立信任</strong>——对内让管理层信任，对外让客户信任。</li><li><strong>QM（质量管理）</strong>：以组织为中心，涉及质量方针、质量目标、质量策划、质量改进等战略层面的活动。QM 追求的是质量经营的卓越。</li></ul><p>三者的关系：QM 提供方向和框架，QA 确保过程受控，QC 执行具体检验和测量，形成一个从战略到执行的完整闭环。</p><hr><h2 id="质量成本" tabindex="-1">质量成本 <a class="header-anchor" href="#质量成本" aria-label="Permalink to &quot;质量成本&quot;">​</a></h2><p>质量成本（Cost of Quality, COQ）是衡量质量经济性的重要指标，通常分为以下四类：</p><table tabindex="0"><thead><tr><th>类别</th><th>定义</th><th>示例</th><th>最优策略</th></tr></thead><tbody><tr><td><strong>预防成本</strong>（Prevention Costs）</td><td>为预防缺陷而投入的费用</td><td>培训、流程设计、供应商评估、预防性维护</td><td>适度增加</td></tr><tr><td><strong>鉴定成本</strong>（Appraisal Costs）</td><td>为评估质量而进行的检验和测试费用</td><td>来料检验、过程检验、出货检验、测试设备校准</td><td>合理控制</td></tr><tr><td><strong>内部失败成本</strong>（Internal Failure Costs）</td><td>产品交付客户前发现缺陷产生的费用</td><td>报废、返工、停工待料、降级处理</td><td>大幅降低</td></tr><tr><td><strong>外部失败成本</strong>（External Failure Costs）</td><td>产品交付客户后发现缺陷产生的费用</td><td>客户投诉处理、退货、保修索赔、法律诉讼、商誉损失</td><td>极力避免</td></tr></tbody></table><p>传统观念认为提高质量需要增加成本，但质量成本理论揭示了一个重要结论：<strong>增加预防成本可以显著降低失败成本</strong>，从而降低总质量成本。克劳士比的研究表明，许多企业的质量成本占销售额的 15%~20%，而卓越运营的企业可以将这一比例降低到 2%~4%。</p><h3 id="质量成本的优化原则" tabindex="-1">质量成本的优化原则 <a class="header-anchor" href="#质量成本的优化原则" aria-label="Permalink to &quot;质量成本的优化原则&quot;">​</a></h3><ol><li>在预防阶段投入 1 元，可在鉴定阶段节省 10 元，在失败阶段节省 100 元——这就是著名的 <strong>1:10:100 法则</strong></li><li>目标是将质量成本从<strong>高失败成本 + 低预防成本</strong>模式，转变为<strong>低失败成本 + 适度预防成本</strong>模式</li><li>持续监控四类成本的占比变化，将其作为质量体系改进的输入</li></ol><hr><p>通过学习本章，您已经对质量工程的演进历史、核心思想、组织结构和经济性有了全面了解。接下来可以在<a href="./statistics-basics">统计基础</a>章节学习质量工程所需的数学工具。</p>',40)])])}const p=a(e,[["render",l]]);export{c as __pageData,p as default};
